#!/usr/bin/env bash
set -euo pipefail

if [[ ! -d .git ]]; then
  echo "Run this script from the root of your GitHub Codespace repository." >&2
  exit 1
fi

printf '%s\n' "Installing the complete Hardline v0.1.0 source tree..."

python3 - <<'PY'
import base64
from pathlib import Path
payload = r''''''
Path('/tmp/hardline-source.tar.gz').write_bytes(base64.b64decode(payload))
PY

tar -xzf /tmp/hardline-source.tar.gz -C .
rm -f /tmp/hardline-source.tar.gz bootstrap-hardline.sh

printf '%s\n' "Installing dependencies and validating the build..."
npm ci
npm run build
npm test

git add -A
if ! git config user.name >/dev/null; then
  git config user.name "Rohit Singh"
fi
if ! git config user.email >/dev/null; then
  git config user.email "singh38600@gmail.com"
fi

if git diff --cached --quiet; then
  echo "No changes to commit. Hardline is already installed."
else
  git commit -m "feat: launch Hardline agent policy compiler"
fi

git push origin HEAD:main

echo
echo "Hardline is live: https://github.com/singh38600-svg/hardline"
